INSERT INTO seed_node (node_key, parent_key, order_index, node_type, checkpoint_type, selection_type, required_count, title, description, reason, layout_role, layout_group, layout_rank, layout_order, estimated_hours, difficulty_level, priority, position_x, position_y, metadata, is_required, is_trackable, learning_outcomes, completion_criteria) VALUES
('ph-bi-foundations', NULL, 100, 'phase', NULL, NULL, NULL, 'BI Foundations and Business Context', 'Build the business intelligence mindset, analytics vocabulary, stakeholder focus, and decision-support context required for BI work.', 'This node builds practical BI analyst capability in bi foundations and business context.', 'trunk', 'ph-bi-foundations', 1, 0, 14, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/bi-analyst", "visualRule": "main_spine"}'::jsonb, true, false, '["Explain the purpose of the BI Foundations and Business Context phase and its role in the full business intelligence path.", "Connect the phase topics to concrete business intelligence deliverables.", "Identify the artifacts or evidence needed before progressing."]'::jsonb, '["Summarize the key concepts covered in BI Foundations and Business Context.", "Identify completed and incomplete child topics or projects.", "Prepare notes or artifacts that show readiness for the next phase."]'::jsonb),
('grp-bi-role-mindset', 'ph-bi-foundations', 110, 'choice_group', NULL, 'complete_all', NULL, 'BI Role, Mindset, and Analytics Lifecycle', 'Group related options around BI Role, Mindset, and Analytics Lifecycle so learners can complete the required selection model without changing the main phase structure.', 'This node builds practical BI analyst capability in bi role, mindset, and analytics lifecycle.', 'side', 'ph-bi-foundations', 1, 10, 2, 'beginner', 110, NULL, NULL, '{"selectionType": "complete_all", "source": "roadmap.sh/bi-analyst"}'::jsonb, true, false, '["Compare the options or grouped topics inside BI Role, Mindset, and Analytics Lifecycle.", "Select or complete the required children according to the group rule.", "Explain how the selected work supports practical business intelligence readiness."]'::jsonb, '["Complete the required number of child nodes for this group.", "Document why the selected options fit the learner''s target direction or project needs.", "Confirm that required child projects or topics have reviewable evidence."]'::jsonb),
('bi-analyst-role', 'grp-bi-role-mindset', 1, 'topic', NULL, NULL, NULL, 'BI Analyst Role and Responsibilities', 'Understand the BI analyst role, common deliverables, collaboration with business stakeholders, and how BI supports data-driven decisions.', 'This node builds practical BI analyst capability in bi analyst role and responsibilities.', 'side', 'ph-bi-foundations', 1, 101, 2, 'beginner', 1, NULL, NULL, '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-bi-role-mindset"}'::jsonb, true, true, '["Explain BI Analyst Role and Responsibilities through business question, metric definition, data evidence, and stakeholder communication.", "Apply BI Analyst Role and Responsibilities in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining BI Analyst Role and Responsibilities with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('business-intelligence-vs-analytics', 'grp-bi-role-mindset', 2, 'topic', NULL, NULL, NULL, 'Business Intelligence vs Analytics', 'Differentiate BI reporting, descriptive analytics, diagnostic analytics, data analytics, data science, and analytics engineering.', 'This node builds practical BI analyst capability in business intelligence vs analytics.', 'side', 'ph-bi-foundations', 1, 102, 2, 'beginner', 2, NULL, NULL, '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-bi-role-mindset"}'::jsonb, true, true, '["Explain Business Intelligence vs Analytics through business question, metric definition, data evidence, and stakeholder communication.", "Apply Business Intelligence vs Analytics in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining Business Intelligence vs Analytics with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('analytics-lifecycle', 'grp-bi-role-mindset', 3, 'topic', NULL, NULL, NULL, 'Analytics Lifecycle', 'Learn how questions move from business problem to data sourcing, modeling, analysis, visualization, delivery, and iteration.', 'This node builds practical BI analyst capability in analytics lifecycle.', 'side', 'ph-bi-foundations', 1, 103, 2, 'beginner', 3, NULL, NULL, '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-bi-role-mindset"}'::jsonb, true, true, '["Explain Analytics Lifecycle through business question, metric definition, data evidence, and stakeholder communication.", "Apply Analytics Lifecycle in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining Analytics Lifecycle with a concrete example.", "Use the topic to produce a metric note, report sketch, dashboard mockup, or analysis artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
('data-driven-decision-making', 'grp-bi-role-mindset', 4, 'topic', NULL, NULL, NULL, 'Data-Driven Decision Making', 'Translate business decisions into measurable questions, metrics, evidence, and recommended actions.', 'This node builds practical BI analyst capability in data-driven decision making.', 'side', 'ph-bi-foundations', 1, 104, 2, 'beginner', 4, NULL, NULL, '{"source": "roadmap.sh/bi-analyst", "parentGroup": "grp-bi-role-mindset"}'::jsonb, true, true, '["Explain Data-Driven Decision Making through data structure, validation, access patterns, and reliability trade-offs.", "Apply Data-Driven Decision Making in a realistic business intelligence task.", "Identify trade-offs, risks, debugging signals, or quality checks related to the topic."]'::jsonb, '["Create or update notes explaining Data-Driven Decision Making with a concrete example.", "Use the topic to produce a query, schema, validation note, or data-quality artifact.", "Record at least two decisions, risks, or validation checks that prove applied understanding."]'::jsonb),
