('chk-final-bi-review', 'ph-portfolio-career', 1480, 'checkpoint', 'gate', NULL, NULL, 'Final BI Roadmap Review Gate', 'Validate readiness after Portfolio, Interview Readiness, and Capstone by requiring evidence that the learner can present completed projects with clear evidence, explain design decisions in interview-ready language, and identify remaining weaknesses and next improvements.', 'Final BI Roadmap Review Gate verifies practical readiness for the next roadmap stage without changing the visual phase structure.', 'checkpoint', 'ph-portfolio-career', 14, 80, 2, 'advanced', 1480, NULL, NULL, '{"gateFor": "ph-portfolio-career", "source": "roadmap.sh/bi-analyst"}'::jsonb, true, true, '["Explain the key decisions, trade-offs, and risks from Portfolio, Interview Readiness, and Capstone.", "Apply the phase knowledge to a realistic business intelligence scenario or artifact.", "Identify gaps, failure modes, or review items before moving to the next phase."]'::jsonb, '["Present completed projects with clear evidence.", "Explain design decisions in interview-ready language.", "Identify remaining weaknesses and next improvements.", "Translate business questions into metrics and reports.", "Capture the result as notes, code, diagrams, tests, screenshots, reports, or another reviewable artifact."]'::jsonb),
